 public CompiledShuffleFragment emit(ShuffleModel.Segment segment,Name keyTypeName,Name valueTypeName,StageBlock stageBlock)throws IOException {
 Precondition.checkMustNotBeNull(segment,"segment");
 Precondition.checkMustNotBeNull(stageBlock,"stageBlock");
 LOG.debug("",segment);
