package org.rubypeople.rdt.internal.compiler.util;
 public final class HashtableOfLong {
 public long [ ] keyTable;
 public Object [ ] valueTable;
 public int elementSize;
 int threshold;
 public HashtableOfLong(){
 this(13);
 }
 public HashtableOfLong(int size){
 this.elementSize = 0;
 this.threshold = size;
 int extraRoom =(int)(size * 1.75f);
 if(this.threshold == extraRoom)extraRoom ++;
 this.keyTable = new long [ extraRoom ];
 this.valueTable = new Object [ extraRoom ];
 }
 public boolean containsKey(long key){
 int length = keyTable.length,index =((int)(key >>> 32))% length;
 long currentKey;
 while((currentKey = keyTable [ index ])!= 0){
 if(currentKey == key)return true;
 if(++ index == length){
 index = 0;
 }
 }
 return false;
 }
 public Object get(long key){
 int length = keyTable.length,index =((int)(key >>> 32))% length;
 long currentKey;
 while((currentKey = keyTable [ index ])!= 0){
 if(currentKey == key)return valueTable [ index ];
 if(++ index == length){
 index = 0;
 }
 }
 return null;
 }
 public Object put(long key,Object value){
 int length = keyTable.length,index =((int)(key >>> 32))% length;
 long currentKey;
 while((currentKey = keyTable [ index ])!= 0){
 if(currentKey == key)return valueTable [ index ] = value;
 if(++ index == length){
 index = 0;
 }
 }
 keyTable [ index ] = key;
 valueTable [ index ] = value;
 if(++ elementSize > threshold)rehash();
 return value;
 }
 private void rehash(){
 HashtableOfLong newHashtable = new HashtableOfLong(elementSize * 2);
 long currentKey;
 for(int i = keyTable.length;
 -- i >= 0;
)if((currentKey = keyTable [ i ])!= 0)newHashtable.put(currentKey,valueTable [ i ]);
 this.keyTable = newHashtable.keyTable;
 this.valueTable = newHashtable.valueTable;
 this.threshold = newHashtable.threshold;
 }
 public int size(){
 return elementSize;
 }
 public String toString(){
 String s = "";
 Object object;
 for(int i = 0,length = valueTable.length;
 i < length;
 i ++)if((object = valueTable [ i ])!= null)s += keyTable [ i ] + " -> " + object.toString()+ "n";
 return s;
 }
 }

