 ExecutableAnalyzer a = new ExecutableAnalyzer(context.environment,context.element);
 if(a.isAbstract()== false){
 a.error("");
 }
 if(a.getReturnType().isVoid()== false){
 a.error("");
 }
 if(a.getParameterType(0).isModel()== false){
 a.error(0,"");
 }
 for(int i = 1,n = a.countParameters();
 i < n;
 i ++){
 a.error(i,"");
 }
 if(a.hasError()){
 return null;
 }
 ShuffleKey key = a.getParameterKey(0);
 if(key == null){
 a.error("");
 return null;
 }
 if(a.hasError()){
 return null;
 }
 Builder builder = new Builder(getTargetAnnotationType(),context);
 builder.addAttribute(FlowBoundary.SHUFFLE);
 builder.addAttribute(a.getObservationCount());
 builder.setDocumentation(a.getExecutableDocument());
 builder.addInput(a.getParameterDocument(0),a.getParameterName(0),a.getParameterType(0).getType(),0,key);
 builder.addOutput("","unique",a.getParameterType(0).getType(),a.getParameterName(0),null);
 builder.addOutput("","duplicated",a.getParameterType(0).getType(),a.getParameterName(0),null);
 return builder.toDescriptor();
 }
 @ Override protected List < ? extends TypeBodyDeclaration > override(Context context){
 ImplementationBuilder builder = new ImplementationBuilder(context);
 ModelFactory f = context.environment.getFactory();
 builder.addStatement(new TypeBuilder(f,context.importer.toType(UnsupportedOperationException.class)).newObject(Models.toLiteral(f,"")).toThrowStatement());
 return builder.toImplementation();
 }
 }

