package org.rubypeople.rdt.internal.core;
 import java.util.HashSet;
 import java.util.Iterator;
 import org.rubypeople.rdt.core.IRubyElement;
 import org.rubypeople.rdt.core.IRubyElementDelta;
 import org.rubypeople.rdt.core.IRubyProject;
 import org.rubypeople.rdt.core.ISourceFolderRoot;
 import org.rubypeople.rdt.core.RubyModelException;
 public class ModelUpdater {
 HashSet projectsToUpdate = new HashSet();
 protected void addToParentInfo(Openable child){
 Openable parent =(Openable)child.getParent();
 if(parent != null && parent.isOpen()){
 try {
 RubyElementInfo info =(RubyElementInfo)parent.getElementInfo();
 info.addChild(child);
 }
 catch(RubyModelException e){
 }
 }
 }
 protected static void close(Openable element){
 try {
 element.close();
 }
 catch(RubyModelException e){
 }
 }
 protected void elementAdded(Openable element){
 int elementType = element.getElementType();
 if(elementType == IRubyElement.RUBY_PROJECT){
 addToParentInfo(element);
 this.projectsToUpdate.add(element);
 }
 else {
 addToParentInfo(element);
 close(element);
 }
 switch(elementType){
 case IRubyElement.SOURCE_FOLDER_ROOT : this.projectsToUpdate.add(element.getRubyProject());
 break;
 case IRubyElement.SOURCE_FOLDER : RubyProject project =(RubyProject)element.getRubyProject();
 project.resetCaches();
 break;
 }
 }
 protected void elementChanged(Openable element){
 close(element);
 }
 protected void elementRemoved(Openable element){
 if(element.isOpen()){
 close(element);
 }
 removeFromParentInfo(element);
 int elementType = element.getElementType();
 switch(elementType){
 case IRubyElement.RUBY_MODEL : break;
 case IRubyElement.RUBY_PROJECT : RubyModelManager manager = RubyModelManager.getRubyModelManager();
 RubyProject javaProject =(RubyProject)element;
 manager.removePerProjectInfo(javaProject);
 manager.containerRemove(javaProject);
 break;
 case IRubyElement.SOURCE_FOLDER_ROOT : this.projectsToUpdate.add(element.getRubyProject());
 break;
 case IRubyElement.SOURCE_FOLDER : RubyProject project =(RubyProject)element.getRubyProject();
 project.resetCaches();
 break;
 }
 }
 public void processRubyDelta(IRubyElementDelta delta){
 try {
 this.traverseDelta(delta,null,null);
 Iterator iterator = this.projectsToUpdate.iterator();
 while(iterator.hasNext()){
 RubyProject project =(RubyProject)iterator.next();
 project.updateSourceFolderRoots();
 }
 }
 finally {
 this.projectsToUpdate = new HashSet();
 }
 }
 protected void removeFromParentInfo(Openable child){
 Openable parent =(Openable)child.getParent();
 if(parent != null && parent.isOpen()){
 try {
 RubyElementInfo info =(RubyElementInfo)parent.getElementInfo();
 info.removeChild(child);
 }
 catch(RubyModelException e){
 }
 }
 }
 protected void traverseDelta(IRubyElementDelta delta,ISourceFolderRoot root,IRubyProject project){
 boolean processChildren = true;
 Openable element =(Openable)delta.getElement();
 switch(element.getElementType()){
 case IRubyElement.RUBY_PROJECT : project =(IRubyProject)element;
 break;
 case IRubyElement.SOURCE_FOLDER_ROOT : root =(ISourceFolderRoot)element;
 break;
 case IRubyElement.SCRIPT : RubyScript cu =(RubyScript)element;
 if(cu.isWorkingCopy()&& ! cu.isPrimary()){
 return;
 }
 }
 switch(delta.getKind()){
 case IRubyElementDelta.ADDED : elementAdded(element);
 break;
 case IRubyElementDelta.REMOVED : elementRemoved(element);
 break;
 case IRubyElementDelta.CHANGED : if((delta.getFlags()& IRubyElementDelta.F_CONTENT)!= 0){
 elementChanged(element);
 }
 break;
 }
 if(processChildren){
 IRubyElementDelta [ ] children = delta.getAffectedChildren();
 for(int i = 0;
 i < children.length;
 i ++){
 IRubyElementDelta childDelta = children [ i ];
 this.traverseDelta(childDelta,root,project);
 }
 }
 }
 }

