List < ISVDBItemBase > ret = new ArrayList < ISVDBItemBase >();
for(Entry < ISVDBIndex,Set < String > > e : fIndexMap.entrySet()){
for(String fname : e.getValue()){
SVDBFile f = e.getKey().findFile(fname);
List < ISVDBItemBase > r = SVDBSearchUtils.findItemsByName(f,name,types);
ret.addAll(r);
}
}
return ret;
}
public List < ISVDBItemBase > findByPrefixInTypeHierarchy(String prefix,SVDBScopeItem ref_type,Comparator < String > comparator,SVDBItemType...types){
List < ISVDBItemBase > ret = new ArrayList < ISVDBItemBase >();
while(ref_type != null){
for(ISVDBItemBase it : ref_type.getChildren()){
boolean type_match =(types.length == 0);
for(SVDBItemType type : types){
if(it.getType()== type){
type_match = true;
break;
}
}
if(type_match &&(it instanceof ISVDBNamedItem)&&((ISVDBNamedItem)it).getName().toLowerCase().startsWith(prefix)){
ret.add(it);
}
}
if(ref_type.getType()== SVDBItemType.ClassDecl &&((SVDBClassDecl)ref_type).getSuperClass()!= null){
ref_type = findNamedClass(((SVDBClassDecl)ref_type).getSuperClass().getName());
}
else {
ref_type = null;
}
}
return ret;
}
public List < ISVDBItemBase > findByNameInClassHierarchy(String name,ISVDBChildItem scope,SVDBItemType...types){
List < ISVDBItemBase > ret = new ArrayList < ISVDBItemBase >();
while(scope != null && scope.getType()!= SVDBItemType.ClassDecl){
scope = scope.getParent();
}
if(scope == null){
return ret;
}
while(scope != null){
if(scope instanceof ISVDBScopeItem){
for(ISVDBItemBase it :((ISVDBScopeItem)scope).getItems()){
boolean match_type =(types.length == 0);
for(SVDBItemType t : types){
if(it.getType()== t){
match_type = true;
break;
}
}
if(match_type && it instanceof ISVDBNamedItem &&((ISVDBNamedItem)it).getName().equals(name)){
ret.add(it);
}
}
}
scope = findNamedClass(((SVDBClassDecl)scope).getSuperClass().getName());
}
return ret;
}
}

