 setEnabled(false);
 }
 else {
 setVisible(true);
 ConfigContextSearch search = new ConfigContextSearch();
 ConfigurationSession configSession = search.sessionFor(explorerContext);
 if(configSession == null){
 setEnabled(false);
 }
 else {
